    public Object handleTicker(Client client, Object message)
    {
        //
        //   {
        //       "method": "market_update",
        //       "params": [
        //         "BTC_USDT",
        //         {
        //           "close": "22293.86",
        //           "deal": "1986990019.96552952",
        //           "high": "24360.7",
        //           "last": "22293.86",
        //           "low": "20851.44",
        //           "open": "24076.12",
        //           "period": 86400,
        //           "volume": "87016.995668"
        //         }
        //       ],
        //       "id": null
        //   }
        //
        Object tickers = this.safeValue(message, "params", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object marketId = this.safeString(tickers, 0);
        Object market = this.safeMarket(marketId, null);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object rawTicker = this.safeValue(tickers, 1, new java.util.HashMap<String, Object>() {{}});
        Object messageHash = Helpers.add(Helpers.add("ticker", ":"), symbol);
        Object ticker = this.parseTicker(rawTicker, market);
        Helpers.addElementToObject(this.tickers, symbol, ticker);
        // watchTicker
        client.resolve(ticker, messageHash);
        // watchTickers
        Object messageHashes = Helpers.objectKeys(client.futures);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(messageHashes)); i++)
        {
            Object currentMessageHash = Helpers.GetValue(messageHashes, i);
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(currentMessageHash, "tickers"), 0)) && Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(currentMessageHash, symbol), 0))))
            {
                // Example: user calls watchTickers with ['LTC/USDT', 'ETH/USDT']
                // the associated messagehash will be: 'tickers:LTC/USDT:ETH/USDT'
                // since we only have access to a single symbol at a time
                // we have to do a reverse lookup into the tickers hashes
                // and check if the current symbol is a part of one or more
                // tickers hashes and resolve them
                // user might have multiple watchTickers promises
                // watchTickers ( ['LTC/USDT', 'ETH/USDT'] ), watchTickers ( ['ETC/USDT', 'DOGE/USDT'] )
                // and we want to make sure we resolve only the correct ones
                client.resolve(ticker, currentMessageHash);
            }
        }
        return message;
    }

